var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>벨제부브의 예언을 따르는 이교도들이 그라운드 원의 대균열 붕괴를 유도했다</color>…","JPN":"<color=#ffd34c>ベルゼブブの予言に従う異教徒たちが、グラウンド・ワンの大亀裂崩壊を誘導した</color>……","ENG":"<color=#ffd34c>The heretics who follow Beelzebub's prophecy orchestrated the collapse of the Grand Dimension Crevice in Ground One</color>...","TWN":"<color=#ffd34c>追隨別西卜預言的異教徒，引發了G1的大峽谷瓦解</color>……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만, 조사를 진행할수록 놈들은 그라운드 원뿐만 아니라 여섯 대균열 모두를 노렸다는 정황이 드러나고 있어.","JPN":"だが調査を進めるにつれて、やつらはグラウンド・ワンだけでなく6つの大亀裂すべてを狙っていたということが明らかになってきている。","ENG":"But the deeper we investigate, the more evidence suggests they were targeting not just Ground One, but all six Grand Dimension Crevices.","TWN":"然而隨著調查深入，逐漸浮現他們的目標不只G1，而是六座大峽谷。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그리고 뒤이어 일어난 사태를 생각해보면, 이 모든 게 타기리온을 돕기 위한 방해공작인 것으로 끼워 맞춰지지.","JPN":"そして後に起きた事件を考えると、すべてがタギリオンを助けるための妨害工作だったということがわかる。","ENG":"And considering what followed, it all lines up as sabotage meant to aid Thagirion.","TWN":"再結合後續發生的事件來看，這一切很可能是為了協助塔基里翁的干擾行動。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…그래. 타기리온이 미리 황금나무의 뿌리를 안배해둔 게 아니라면, 대균열 붕괴가 일어나자마자 그런 일이 일어날 수는 없었을 테니 말이야.","JPN":"……ああ。タギリオンが黄金の木の根を手配しておいたから、大亀裂崩壊直後にああいう事件が起りえたんだ。","ENG":"...Right. Unless Thagirion had already planted the Golden Tree's roots in advance, none of that could have happened the instant the Grand Dimension Crevice collapsed.","TWN":"……沒錯。若不是塔基里翁事先安排好黃金樹的根系，大峽谷一瓦解，不可能立刻引發那種事態。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 우리가 지금껏 조사해왔던 벨제부브는 남을 돕기 위해 움직이지 않아.","JPN":"でも私たちが今まで調べてきたベルゼブブは、他人を助けるために動くような者ではない。","ENG":"But the Beelzebub we've investigated so far doesn't act to help others.","TWN":"但我們至今調查過的別西卜，從來不是會為他人行動的類型。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하물며 그게 다른 마왕이라면 더더욱 그렇지.","JPN":"相手が他の魔王ならなおさらだ。","ENG":"Especially not another Demon Lord.","TWN":"更別說對象還是另一名魔王。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면, 검은 죽음은 과연 무엇을 얻기 위해 대균열을 노린 건가…","JPN":"なら、黒き死はいったい何を得るために大亀裂を狙ったのか……","ENG":"Then what exactly was the Black Death trying to gain by targeting the Grand Dimension Crevices...","TWN":"那麼，黑死究竟是為了得到什麼，才會盯上大峽谷……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"중요한 퍼즐 조각이 하나 빠졌군.","JPN":"重要なパズルのピースが1つ欠けているな。","ENG":"We're missing a crucial piece of the puzzle.","TWN":"缺少了一塊關鍵拼圖。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네의 생각은 어떤가?","JPN":"君の意見はどうかね？","ENG":"What do you think?","TWN":"你的看法呢？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…아이린 애들러.","JPN":"……アイリーン・アドラー。","ENG":"...Irene Adler.","TWN":"……艾琳．艾德勒。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그 말씀처럼, 벨제부브와 타기리온은 협력 관계가 아닙니다.","JPN":"仰った通り、ベルゼブブとタギリオンは協力関係ではありません。","ENG":"As you say, Beelzebub and Thagirion are not allies.","TWN":"正如你所言，別西卜與塔基里翁並非合作關係。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"두 마왕에겐 서로를 이해할 수 있는 접점이 전무하니까요.","JPN":"二人の間には、互いを理解できるような接点は皆無ですから。","ENG":"The two Demon Lords have no common ground to understand each other.","TWN":"兩名魔王之間，不存在任何能互相理解的交集。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사도?","JPN":"使徒？","ENG":"An Apostle?","TWN":"使徒？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"저 녀석이 왜 아직도 살아있는 거지?","JPN":"なぜあいつがまだ生きている？","ENG":"Why is that thing still alive?","TWN":"那傢伙為什麼還活著？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"사도 스완은 자신이 타기리온에게 숙청 당할 것을 알고 있었습니다.","JPN":"使徒スワンは自分がタギリオンに粛清されることを予想していました。","ENG":"Apostle Swan knew she would be purged by Thagirion.","TWN":"使徒史旺早就知道，自己終將被塔基里翁肅清。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래서 심장 없이도 메신저로서의 역할을 다할 수 있는 방법을 미리 모색해둔 거죠.","JPN":"だから心臓がなくてもメッセンジャーとしての役目を果たせる方法を模索しておいたんです。","ENG":"So she prepared a way to fulfill her role as a messenger even without a heart.","TWN":"因此，她事先尋找即使沒有心臟，也能作為信使存在的方法。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"뭐, 마왕의 사도가 되어버린 시점에서 살아있다는 표현은 모순되지만요.","JPN":"まあ、魔王の使徒になった時点で「生きている」という表現は矛盾していますが。","ENG":"Well, calling her \\"alive\\" is a contradiction the moment one becomes a Demon Lord's Apostle.","TWN":"不過在成為魔王使徒的那一刻，活著這個說法本身就已經是矛盾了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"…한시가 바쁘니 핵심만 짚도록 하죠.","JPN":"……一刻を争う状況なので、本題に入ります。","ENG":"...Time is short, so let's get to the point.","TWN":"……時間緊迫，我就直說重點。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"지금 현실을 침범하고 있는 황금나무는 타기리온이 의도한 것보다 이른 시기에 뿌리를 내렸습니다.","JPN":"今現実を侵している黄金の木は、タギリオンが意図していた時期よりも早く根を下ろしました。","ENG":"The Golden Tree now encroaching on reality took root earlier than Thagirion intended.","TWN":"如今入侵現實的黃金樹，比塔基里翁原本預期的時間更早扎根。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그게 무슨 소리지? 지금 사태를 타기리온이 의도한 게 아니었다고?","JPN":"何だと？　今の事態はタギリオンが意図していたものと違うというのか？","ENG":"What do you mean? Are you saying this disaster wasn't part of Thagirion's plan?","TWN":"這是什麼意思？現在的事態，並非塔基里翁原先的計畫？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 뭘 위해 저런 재앙을 심어 뒀다는 거야?","JPN":"ならば、何のためにあのような災害を植えておいたんだ？","ENG":"Then why plant something like that in the first place?","TWN":"那他究竟是為了什麼，才在現實埋下這樣的災厄？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"본래는 클리포트 게임이 한창 진행될 때, 클리파 차원으로 진격하는 여러분의 전력을 분산시킬 목적으로 쓰일 예정이었죠.","JPN":"本来はクリフォトゲームの真っ最中に、クリファ次元に進撃する皆さんの戦力を分散させるためのものでした。","ENG":"Originally, it was meant to be used during the Qliphoth Game, to disperse your forces as you advanced into the Qlipha Dimension.","TWN":"原本是打算在逆卡巴拉遊戲進行期間，用來分散你們進攻逆卡巴拉次元的戰力。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…클리포트 게임이 시작된 뒤라고?","JPN":"……クリフォトゲームが開始した後だと？","ENG":"...After the Qliphoth Game began?","TWN":"……是在遊戲開始之後？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"そうか。","ENG":"I see.","TWN":"原來如此。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"펜릴 소대를 비롯한 주요 전력이 마왕에게로 향한 시점에서 이런 일이 벌어졌다면, 지금처럼 수습할 여력은 없었겠지.","JPN":"フェンリル小隊をはじめとする主要戦力が魔王に向かっている時にこんなことが起きたら、こうして収拾できる余力はなかっただろう。","ENG":"If this had happened when our main forces, including Fenrir Squad, were already moving on the Demon Lord, we wouldn't have had the capacity to contain it like we did now.","TWN":"若是在芬里爾小隊等主力前往魔王之時才發生，我們現在恐怕根本無力收拾。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"맞아요. 미리 알고 있어도 대응할 수 없는 완벽한 각본이었죠.","JPN":"そうです。予測できたとしても対応できない、完璧な脚本でした。","ENG":"Exactly. It was a perfect script, impossible to respond to even if you knew in advance.","TWN":"沒錯。即便事先知曉，也無法防範的完美劇本。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"하지만 누군가의 방해공작이 그 시기를 앞당겼습니다.","JPN":"ですが誰かの妨害工作によってその時期は早まりました。","ENG":"But someone's interference pushed the timing forward.","TWN":"但某人的干擾，讓時機提前了。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"벨제부브가…","JPN":"ベルゼブブは……","ENG":"Beelzebub...","TWN":"別西卜……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 녀석은 오히려 타기리온의 계획에 훼방을 놓은 셈이란 건가.","JPN":"やつはタギリオンの計画を手伝ったわけではなく、逆に邪魔したということか。","ENG":"So that means they actually disrupted Thagirion's plan.","TWN":"反而是他，破壞了塔基里翁的計畫啊。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 타기리온과 그 사도들은 어째서 현실에 강림했던 거지?","JPN":"なら、タギリオンとその使徒たちはなぜ現実に降臨した？","ENG":"Then why did Thagirion and her Apostles descend into reality?","TWN":"那塔基里翁與她的使徒，為什麼還要降臨現實？"},"stage":{"bg":"OFFICE_TOP","slots":{"L":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"그녀가 필요로 하는 것이 현실에 있었으니까요.","JPN":"彼女が必要としているものが現実にあったからです。","ENG":"Because what she needed was here, in reality.","TWN":"因為她需要的東西，就在現實中。"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"IRENE_CHARADE_NPC_NULL","text":{"KOREA":"예정대로였다면 당신들이 부재인 때를 노려 손쉽게 취할 수 있었을 테지만…","JPN":"予定通りなら、あなたたちが不在の隙を狙って簡単に手に入れることができたのですが……","ENG":"If things had gone as planned, she could have taken it easily while you were absent...","TWN":"若一切照計畫進行，她本可趁你們不在時輕易取走……"},"stage":{"bg":"OFFICE_TOP","slots":{"L":null,"C":{"char_id":"IRENE_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};